import * as React from 'react';

// ─── Types ────────────────────────────────────────────────────────────────────

export interface OtaIconProps {
  className?: string;
  style?: React.CSSProperties;
  'aria-hidden'?: boolean | 'true' | 'false';
  'aria-label'?: string;
}

/** Custom OTA icon component — compatible with the <Icon> wrapper */
export type OtaIcon = React.FC<OtaIconProps>;

// ─── Factory ──────────────────────────────────────────────────────────────────

function makeIcon(viewBox: string, children: React.ReactNode, name: string): OtaIcon {
  const [, , w, h] = viewBox.split(' ').map(Number);
  const Comp: OtaIcon = ({ className, style, 'aria-hidden': ah, 'aria-label': al }) => (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox={viewBox}
      width={w}
      height={h}
      fill="currentColor"
      className={className}
      style={style}
      aria-hidden={ah}
      aria-label={al}
    >
      {children}
    </svg>
  );
  Comp.displayName = name;
  return Comp;
}

